import{_ as t,o as r,c as a,a4 as s}from"./chunks/framework.CcEU2j4W.js";const m=JSON.parse('{"title":"Development Workflow","description":"","frontmatter":{},"headers":[],"relativePath":"reference/guides/development.md","filePath":"reference/guides/development.md"}'),i={name:"reference/guides/development.md"};function o(n,e,d,c,l,p){return r(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="development-workflow" tabindex="-1">Development Workflow <a class="header-anchor" href="#development-workflow" aria-label="Permalink to &quot;Development Workflow&quot;">​</a></h1><blockquote><p><strong>Last Updated</strong>: 2026-06-28</p></blockquote><h2 id="coding-conventions" tabindex="-1">Coding Conventions <a class="header-anchor" href="#coding-conventions" aria-label="Permalink to &quot;Coding Conventions&quot;">​</a></h2><p>Conventions are defined in the project&#39;s <code>CLAUDE.md</code> and the global CodeOps coding standards. Highlights specific to this codebase:</p><ul><li><strong>ESM-only, zero runtime dependencies</strong> — pure-JS only; the <code>check:deps</code> guard fails any native runtime dep (<a href="/jsvision/pr-preview/pr-167/reference/decisions/ADR-001-esm-zero-dependency.html">ADR-001</a>).</li><li><strong>Foundation-first layering</strong> with a single public entry point (<code>src/engine/index.ts</code>); every subsystem re-exports its public symbols there. Target 200–500 lines per file.</li><li><strong>NodeNext import specifiers</strong> use the <code>.js</code> extension even for <code>.ts</code> sources (e.g. <code>from &#39;./version.js&#39;</code>).</li><li><strong>Public/exported symbols carry JSDoc</strong> (purpose, params, returns, side effects).</li><li><strong>Tests live in <code>test/</code> only</strong> — never colocated with source.</li></ul><h2 id="branch-strategy" tabindex="-1">Branch Strategy <a class="header-anchor" href="#branch-strategy" aria-label="Permalink to &quot;Branch Strategy&quot;">​</a></h2><p>Main branch is <code>master</code>. Work on feature branches; commit scope is the area touched (<code>scaffold</code>, <code>render</code>, <code>color</code>, <code>host</code>, <code>safety</code>, <code>tests</code>, <code>docs</code>, …). Run <code>npm run verify</code> before every commit.</p><h2 id="testing-strategy" tabindex="-1">Testing Strategy <a class="header-anchor" href="#testing-strategy" aria-label="Permalink to &quot;Testing Strategy&quot;">​</a></h2><p>Tests are plain <code>node:test</code> run through <code>tsx</code> — no third-party test framework. They follow a strict split (see the project&#39;s testing standards):</p><ul><li><strong><code>*.spec.test.ts</code></strong> — specification tests. An <strong>immutable oracle</strong> derived from requirements/acceptance criteria, never from reading the implementation. If a spec test fails after a change, the implementation is wrong, not the test.</li><li><strong><code>*.impl.test.ts</code></strong> — implementation/edge-case tests (internals, error paths).</li><li><strong><code>*.e2e.test.ts</code></strong> — end-to-end (run explicitly or via <code>npm run gate</code>).</li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                                    # unit tiers (spec + impl)</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tsx</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --test</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test/host-tier3.e2e.test.ts</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # RD-09 Tier-3: restore on every exit path</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gate</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                                # full go/no-go gate</span></span></code></pre></div><p>The four test tiers (RD-09): a data-driven input corpus, golden-screen via <code>@xterm/headless</code> across all colour depths, the no-PTY Tier-3 restore e2e, and seeded decoder fuzz + byte-proportionality. RD-10 adds the perf-budget ceiling, the esbuild tree-shake check, the a11y/degradation golden tests, and the detection-budget test.</p><h2 id="spec-first-task-ordering" tabindex="-1">Spec-First Task Ordering <a class="header-anchor" href="#spec-first-task-ordering" aria-label="Permalink to &quot;Spec-First Task Ordering&quot;">​</a></h2><p>The project follows CodeOps spec-first ordering: write spec tests → confirm red → implement → confirm green → add impl tests → full verify. A <code>*.spec.test.ts</code> is an immutable oracle; do not weaken it to match broken code.</p><h2 id="common-patterns" tabindex="-1">Common Patterns <a class="header-anchor" href="#common-patterns" aria-label="Permalink to &quot;Common Patterns&quot;">​</a></h2><h3 id="pure-transform-injectable-seam" tabindex="-1">Pure transform + injectable seam <a class="header-anchor" href="#pure-transform-injectable-seam" aria-label="Permalink to &quot;Pure transform + injectable seam&quot;">​</a></h3><p>Rendering, decoding, and colour encoding are pure functions; side effects live behind a seam (<code>RuntimeAdapter</code>, <code>TerminalQuery</code>, <code>StyleEncoder</code>). When adding behaviour, prefer a pure function plus a seam over reaching for a Node API directly (<a href="/jsvision/pr-preview/pr-167/reference/decisions/ADR-003-pure-core-injectable-seams.html">ADR-003</a>).</p><h3 id="capability-driven-rendering" tabindex="-1">Capability-driven rendering <a class="header-anchor" href="#capability-driven-rendering" aria-label="Permalink to &quot;Capability-driven rendering&quot;">​</a></h3><p>Draw real Unicode/colour into the buffer; let <code>serialize</code> + the <code>StyleEncoder</code> and glyph fallback downgrade output to the detected capability. There is no second buffer for &quot;ASCII mode&quot; — the same frame renders correctly on a capable or a minimal terminal.</p><h3 id="untrusted-text-→-sanitize" tabindex="-1">Untrusted text → <code>sanitize</code> <a class="header-anchor" href="#untrusted-text-→-sanitize" aria-label="Permalink to &quot;Untrusted text → `sanitize`&quot;">​</a></h3><p>Any text derived from untrusted input must reach cells only through <code>sanitize</code> (<code>ScreenBuffer.text</code> already does this). Never write raw untrusted bytes to the terminal (<a href="/jsvision/pr-preview/pr-167/reference/decisions/ADR-005-sanitize-boundary.html">ADR-005</a>).</p><h2 id="pre-commit-checklist" tabindex="-1">Pre-Commit Checklist <a class="header-anchor" href="#pre-commit-checklist" aria-label="Permalink to &quot;Pre-Commit Checklist&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>Command</th></tr></thead><tbody><tr><td>Verify (build + test)</td><td><code>npm run verify</code></td></tr><tr><td>Lint + format</td><td><code>npm run lint</code></td></tr><tr><td>Dependency policy</td><td><code>npm run check:deps</code></td></tr><tr><td>Acceptance gate (for releases)</td><td><code>npm run gate</code></td></tr></tbody></table>',23)])])}const u=t(i,[["render",o]]);export{m as __pageData,u as default};
